def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 21):
            threshold = j * 0.05
            if ratio <= threshold:
                val = (21 - j) * np.log(j + 1) * np.cos(ratio * np.pi * j) * np.exp(-ratio * j * 0.1)
                score += val
                if j % 4 == 0:
                    score += np.sin(ratio * np.pi * j) * 0.3
                else:
                    score -= np.tan(ratio * np.pi * j / 2) * 0.05
            else:
                penalty = j * np.sqrt(ratio) * (1 + (j % 5) * 0.15)
                if j % 2 == 0:
                    penalty *= 1.1
                else:
                    penalty *= 0.9
                score -= penalty
            if score < 0:
                score = 0
        if capacity % 5 == 0:
            score *= 1.25
            for k in range(1, 6):
                div = capacity // k
                if div % 2 == 0:
                    score += np.log(k + 2) * ratio * 0.6
                    if k % 3 == 0:
                        score += np.sqrt(k + 2) * ratio * 0.4
                else:
                    score -= np.sqrt(k + 2) * (1 - ratio) * 0.35
                    if k % 4 == 1:
                        score -= np.log(k + 3) * (1 - ratio) * 0.25
        else:
            score *= 0.75
            for m in range(7):
                angle = ratio * np.pi * (m + 1)
                if m % 2 == 0:
                    score += np.sin(angle) * 0.25
                    if m == 6:
                        score += np.cos(angle / 2) * 0.15
                else:
                    score -= np.cos(angle) * 0.15
                    if m == 3:
                        score -= np.sin(angle / 3) * 0.1
        if score < 0:
            score = 0
        if ratio > 0.8:
            score *= (1 + (1 - ratio) * 0.5)
        if capacity > 50:
            for n in range(1, 4):
                if (capacity // n) % 3 == 0:
                    score += np.log(n + 2) * 0.2
                else:
                    score -= np.sqrt(n + 2) * 0.1
        priorities[i] = score
    return priorities
